import{_ as a,o as t,c as i,a0 as n}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Analytics Overview","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/overview.md","filePath":"analytics/overview.md"}'),s={name:"analytics/overview.md"};function o(l,e,r,c,h,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="analytics-overview" tabindex="-1">Analytics Overview <a class="header-anchor" href="#analytics-overview" aria-label="Permalink to &quot;Analytics Overview&quot;">​</a></h1><p>The <strong>Analytics</strong> area is where the app turns saved results into trends, rankings, and follow-up views. It is meant for reading patterns across many tracked events, not for entering scores.</p><p>If this is your first premium analytics page, see <a href="./../subscriptions/premium-features.html">Premium Features</a> for how locked and active premium tabs behave.</p><blockquote><p>Screenshot placeholder: <code>analytics-kingdom.png</code> (S49)</p><p>Screenshot placeholder: <code>analytics-alliance.png</code> (S50)</p></blockquote><h2 id="what-the-tabs-are" tabindex="-1">What the tabs are <a class="header-anchor" href="#what-the-tabs-are" aria-label="Permalink to &quot;What the tabs are&quot;">​</a></h2><p>The Analytics page has up to four tabs:</p><ul><li><strong>Kingdom</strong> for kingdom-wide totals, comparisons, and trends</li><li><strong>Alliance</strong> for one alliance&#39;s members, scores, attendance, and watchlists</li><li><strong>Player</strong> for one player&#39;s history across many event instances</li><li><strong>Custom</strong> for a build-your-own chart and table view</li></ul><p>The last two are premium tabs. On a free plan they still appear, but they show a locked card instead of data. The full locked/active pattern is explained on <a href="./../subscriptions/premium-features.html">Premium Features</a>.</p><h2 id="who-can-see-which-tab" tabindex="-1">Who can see which tab <a class="header-anchor" href="#who-can-see-which-tab" aria-label="Permalink to &quot;Who can see which tab&quot;">​</a></h2><ul><li><strong>Kingdom</strong> is for <code>Supreme Admin</code> and <code>King</code> users, plus granted alliances only when an accepted premium kingdom grant includes the kingdom analytics sharing feature. See <a href="./kingdom.html">Kingdom Analytics</a>.</li><li><strong>Alliance</strong> is the everyday analytics tab for alliance-scoped users.</li><li><strong>Player</strong> is available to alliance leadership when the premium player-across-events feature is active.</li><li><strong>Custom</strong> is available when the custom analytics premium feature is active.</li></ul><h2 id="how-scoping-works" tabindex="-1">How scoping works <a class="header-anchor" href="#how-scoping-works" aria-label="Permalink to &quot;How scoping works&quot;">​</a></h2><p>The page only shows data inside your current scope.</p><ul><li><code>Supreme Admin</code> users can work across kingdoms.</li><li><code>King</code> users work inside their kingdom.</li><li><code>Alliance Leader</code>, <code>Co-Leader</code>, and alliance-scoped readers work inside their alliance.</li></ul><p>If you are alliance-only, the <strong>Kingdom</strong> tab is hidden unless your alliance accepted a kingdom grant that specifically shares kingdom analytics. Even then, that kingdom view is still limited to the granted kingdom.</p><p>Inside the page:</p><ul><li>the <strong>Alliance</strong> tab can include an alliance picker when you are allowed to manage more than one alliance</li><li>the <strong>Player</strong> tab opens from a search box or by selecting a player from another analytics tab</li><li>the <strong>Custom</strong> tab applies whatever filters you choose to the data you are already allowed to see</li></ul><h2 id="recalculate-analytics" tabindex="-1">Recalculate analytics <a class="header-anchor" href="#recalculate-analytics" aria-label="Permalink to &quot;Recalculate analytics&quot;">​</a></h2><p>Analytics recalculate automatically as results change, but some settings changes may need a manual refresh. If your role can manage analytics settings, you may see a <strong>Recalculate analytics</strong> button in the analytics settings area.</p><p>Use it when:</p><ul><li>you changed status or attribute rules</li><li>you changed reward-related analytics inputs</li><li>numbers look out of date after an admin change</li></ul><p>Most day-to-day users do not need to use it.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./kingdom.html">Kingdom Analytics</a></li><li><a href="./alliance.html">Alliance Analytics</a></li><li><a href="./player-cross-event.html">Player Cross-Event Analytics</a></li><li><a href="./custom-analytics.html">Custom Analytics Builder</a></li></ul>',23)])])}const p=a(s,[["render",o]]);export{m as __pageData,p as default};
